<script setup lang="ts">import { computed,onMounted,watch } from 'vue';import { useRoute } from 'vue-router';import CourtyardScene from '../components/CourtyardScene.vue';import { world } from '../store/world';const route=useRoute();const teamId=computed(()=>Number(route.params.teamId)),runId=computed(()=>String(route.params.runId));const load=()=>world.loadTeam(teamId.value,runId.value);onMounted(load);watch([teamId,runId],load);</script>
<template><div class="page courtyard-page"><header class="page-heading"><div><span class="eyebrow">卷宗 {{runId}}</span><h1>{{world.state.team?.name}}</h1><p>本次问策已冻结的房间进度与执行时间线。</p></div><div class="page-actions"><RouterLink :to="{name:'dossier',params:{teamId,runId}}">查看结论卷宗</RouterLink><RouterLink :to="{name:'team',params:{teamId}}">返回当前院落</RouterLink></div></header><div v-if="world.state.loading" class="loading-panel">正在调取卷宗……</div><CourtyardScene v-else-if="world.state.run" :team-id="teamId" :rooms="world.state.rooms" :agents="world.state.agents" :run="world.state.run"/></div>
</template>
